(window.webpackJsonp=window.webpackJsonp||[]).push([[6],{633:function(n,r){n.exports='\x3c!-- \r\ntitle: 03-C条件跳转\r\nsort: \r\n--\x3e \r\n# 条件跳转指令\r\n\r\n## while\r\n\r\n```c\r\nwhile(scanf("%ld", &num) == 1);\t\t// 跳过第一个数字\r\nwhile(scanf("%*", &*) == 1)\t\t\t// 获取连续输入\r\n```\r\n\r\n### 运算符号\r\n\r\n- 条件运算：`?:`\r\n\r\n  ```c\r\n  x = (y<0)?y:-y;\t\t// c中唯一一个三元运算符\r\n  ```\r\n\r\n## 跳出\r\n\r\n```c\r\n\twhile(scanf("%d", &i))\r\n\t{\r\n\t\tif (i > 100)\r\n\t\t{\r\n\t\t\tprintf("its too big.\\n");\r\n\t\t\tcontinue;\t\t// 回到while获取输入值\r\n\t\t}\r\n\t\tprintf("its a right nember");\r\n\t\tbreak;\t\t\t\t// 跳出循环\r\n\t}\r\n```\r\n\r\n## 常用库\r\n\r\n- `math.h`\r\n\r\n  > fab(float)：返回浮点数的绝对值（float_abs）\r\n\r\n- `stdbool.h`\r\n\r\n  > typedef _Bool bool\r\n  >\r\n  > 1 true\r\n  >\r\n  > 0 false\r\n  \r\n\r\n## `switch()`\r\n\r\n```c\r\nswitch(x)\r\n{\r\n    case 1:\r\n        printf("1");\r\n        break;\r\n    case 2:\r\n        printf("2");\r\n        break;\r\n    default:\r\n        printf("404")\r\n}\r\n```\r\n\r\n'}}]);